import React, { useState, useEffect } from 'react';

// --- 1. KOMPONEN UI: STAT CARD ---
const StatCard = ({ icon, value, label, color }) => (
  <div style={styles.statCard}>
    <div style={{ ...styles.statIconBox, color: color }}>{icon}</div>
    <div>
      <div style={styles.statValue}>{value}</div>
      <div style={styles.statLabel}>{label}</div>
    </div>
  </div>
);

// --- 2. KOMPONEN UI: PROGRESS BAR ---
const CapacityBar = ({ percentage }) => {
  const isFull = percentage > 85;
  return (
    <>
      <div style={styles.progressBar}>
        <div style={{
          ...styles.progressFill,
          width: `${percentage}%`,
          backgroundColor: isFull ? '#e74c3c' : '#00a37c'
        }}></div>
      </div>
      <span style={{ fontSize: '12px', fontWeight: '600' }}>{Math.round(percentage)}%</span>
    </>
  );
};

// --- 3. KOMPONEN UTAMA: DASHBOARD ---
function Dashboard() {
  const [trashData, setTrashData] = useState([]);
  const [adminData, setAdminData] = useState([]);
  const [activeAdmin, setActiveAdmin] = useState('');
  const [activeMenu, setActiveMenu] = useState('dashboard');

  // Mengambil data dari Backend Flask
  const fetchData = async () => {
    try {
      const [resTrash, resAdmins] = await Promise.all([
        fetch('http://127.0.0.1:5000/api/trash'),
        fetch('http://127.0.0.1:5000/api/admins')
      ]);

      setTrashData(await resTrash.json());
      setAdminData(await resAdmins.json());
    } catch (error) {
      console.error("Koneksi API Gagal:", error);
    }
  };

  // Menghapus Admin dari Database
  const handleDeleteAdmin = async (email) => {
    if (window.confirm(`Hapus permanen admin: ${email}?`)) {
      try {
        const res = await fetch(`http://127.0.0.1:5000/api/admins/${email}`, {
          method: 'DELETE',
        });

        if (res.ok) {
          alert("Data berhasil dihapus dari database!");
          fetchData(); 
        }
      } catch (error) {
        alert("Gagal menghapus data. Cek koneksi server.");
      }
    }
  };

  useEffect(() => {
    setActiveAdmin(localStorage.getItem("nama_aktif") || "Admin");
    fetchData();
    const interval = setInterval(fetchData, 5000); // Auto-refresh 5 detik
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={styles.appContainer}>
      <style>@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;600;700&display=swap');</style>

      {/* --- SIDEBAR SECTION (KIRI) --- */}
      <aside style={styles.sidebar}>
        <div style={styles.logoArea}>
          <div style={styles.logoIcon}>S</div>
          <span style={styles.logoText}>SMART BIN</span>
        </div>

        <nav style={styles.navMenu}>
          <NavItem 
            active={activeMenu === 'dashboard'} 
            label="Dashboard" icon="📊" 
            onClick={() => setActiveMenu('dashboard')} 
          />
          <NavItem 
            active={activeMenu === 'admin'} 
            label="User Admin" icon="👥" 
            onClick={() => setActiveMenu('admin')} 
          />

          {/* --- DATA LOG DI BAWAH USER ADMIN --- */}
          <div style={styles.sidebarLogSection}>
            <h4 style={styles.sidebarLogTitle}>LOG KAPASITAS</h4>
            <div style={styles.sidebarLogContainer}>
              {trashData.length > 0 ? (
                trashData.slice(0, 8).map((log, index) => (
                  <div key={index} style={styles.miniLogCard}>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                      <span style={{ fontWeight: '700' }}>{log.bin_id}</span>
                      <span style={{ fontSize: '10px', opacity: 0.7 }}>{new Date(log.created_at).toLocaleTimeString('id-ID', {hour: '2-digit', minute:'2-digit'})}</span>
                    </div>
                    <div style={{ fontSize: '11px', marginTop: '4px' }}>
                      Kapasitas: <span style={{ color: log.percentage > 85 ? '#ff7675' : '#55efc4' }}>{Math.round(log.percentage)}%</span>
                    </div>
                  </div>
                ))
              ) : (
                <div style={{ fontSize: '11px', opacity: 0.5 }}>Belum ada data...</div>
              )}
            </div>
          </div>

          <div style={styles.logoutBtn} onClick={() => { localStorage.clear(); window.location.href = "/"; }}>
            <span style={styles.navIcon}>🚪</span> Keluar Sistem
          </div>
        </nav>
      </aside>

      {/* --- MAIN CONTENT SECTION (KANAN) --- */}
      <main style={styles.mainContent}>
        <header style={styles.topHeader}>
          <div style={styles.breadcrumb}>Dashboard &gt; {activeMenu === 'dashboard' ? 'Monitoring' : 'Manajemen'}</div>
          <div style={styles.userProfile}>
            <span style={styles.userName}>{activeAdmin}</span>
            <div style={styles.avatar}>👤</div>
          </div>
        </header>

        <div style={styles.contentWrapper}>
          <h2 style={styles.welcomeText}>
            {activeMenu === 'dashboard' ? 'Monitoring Real-time' : 'Daftar Pengelola Admin'}
          </h2>

          {activeMenu === 'dashboard' ? (
            <>
              <div style={styles.statsGrid}>
                <StatCard icon="🗑️" value={trashData.length} label="Total Data Log" color="#008f68" />
                <StatCard icon="👤" value={adminData.length} label="Admin Terdaftar" color="#f39c12" />
                <StatCard icon="📶" value="Online" label="Status Sistem" color="#2ecc71" />
              </div>

              <div style={styles.tableSection}>
                <h3 style={styles.tableTitle}>📊 Detail Tabel Kapasitas</h3>
                <div style={styles.tableCard}>
                  <table style={styles.table}>
                    <thead>
                      <tr>
                        <th style={styles.th}>ID BIN</th>
                        <th style={styles.th}>KAPASITAS</th>
                        <th style={styles.th}>TIPE</th>
                        <th style={styles.th}>STATUS</th>
                        <th style={styles.th}>WAKTU</th>
                      </tr>
                    </thead>
                    <tbody>
                      {trashData.map((item, index) => (
                        <tr key={index} style={styles.tr}>
                          <td style={styles.td}><strong>{item.bin_id}</strong></td>
                          <td style={styles.td}><CapacityBar percentage={item.percentage} /></td>
                          <td style={styles.td}>{item.type}</td>
                          <td style={styles.td}>
                            <span style={item.status === 'penuh' ? styles.badgeRed : styles.badgeGreen}>{item.status}</span>
                          </td>
                          <td style={styles.td}>{new Date(item.created_at).toLocaleTimeString('id-ID')}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </>
          ) : (
            <div style={styles.tableSection}>
              <h3 style={styles.tableTitle}>👥 Database Admin Sistem</h3>
              <div style={styles.tableCard}>
                <table style={styles.table}>
                  <thead>
                    <tr>
                      <th style={styles.th}>NAMA</th>
                      <th style={styles.th}>EMAIL</th>
                      <th style={styles.th}>ROLE</th>
                      <th style={styles.th}>AKSI</th>
                    </tr>
                  </thead>
                  <tbody>
                    {adminData.map((admin, index) => (
                      <tr key={index} style={styles.tr}>
                        <td style={styles.td}><strong>{admin.name}</strong></td>
                        <td style={styles.td}>{admin.email}</td>
                        <td style={styles.td}><span style={styles.badgeGreen}>Admin</span></td>
                        <td style={styles.td}>
                          {admin.name !== activeAdmin ? (
                            <button onClick={() => handleDeleteAdmin(admin.email)} style={styles.deleteButton}>Hapus Akun</button>
                          ) : (
                            <span style={{ fontSize: '11px', color: '#bbb' }}>Akun Anda</span>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

const NavItem = ({ active, label, icon, onClick }) => (
  <div style={active ? styles.navItemActive : styles.navItem} onClick={onClick}>
    <span style={styles.navIcon}>{icon}</span> {label}
  </div>
);

// --- 🎨 OBJEK STYLE (Lengkap) ---
const styles = {
  appContainer: { display: 'flex', minHeight: '100vh', backgroundColor: '#008f68', fontFamily: "'Poppins', sans-serif" },
  sidebar: { width: '280px', backgroundColor: '#008f68', color: '#fff', padding: '30px 0', display: 'flex', flexDirection: 'column' },
  logoArea: { display: 'flex', alignItems: 'center', padding: '0 30px', marginBottom: '40px' },
  logoIcon: { backgroundColor: '#fff', color: '#008f68', width: '38px', height: '38px', borderRadius: '10px', display: 'flex', justifyContent: 'center', alignItems: 'center', fontWeight: 'bold', marginRight: '12px', fontSize: '20px' },
  logoText: { fontSize: '22px', fontWeight: '700' },
  navMenu: { display: 'flex', flexDirection: 'column', flex: 1 },
  navItem: { padding: '16px 30px', cursor: 'pointer', color: '#c1e1d8', display: 'flex', alignItems: 'center', fontSize: '14px', transition: '0.3s' },
  navItemActive: { padding: '16px 30px', cursor: 'pointer', backgroundColor: 'rgba(255,255,255,0.15)', borderLeft: '5px solid #fff', color: '#fff', display: 'flex', alignItems: 'center', fontSize: '14px', fontWeight: '600' },
  navIcon: { marginRight: '15px' },

  // Sidebar Log Section
  sidebarLogSection: { padding: '20px 30px', marginTop: '10px' },
  sidebarLogTitle: { fontSize: '11px', letterSpacing: '1px', opacity: 0.6, marginBottom: '15px', fontWeight: '700' },
  sidebarLogContainer: { overflowY: 'auto', maxHeight: '350px', paddingRight: '5px' },
  miniLogCard: { backgroundColor: 'rgba(255,255,255,0.1)', padding: '12px', borderRadius: '12px', marginBottom: '10px', fontSize: '12px', borderLeft: '3px solid rgba(255,255,255,0.3)' },

  logoutBtn: { padding: '16px 30px', cursor: 'pointer', color: '#ff7675', display: 'flex', alignItems: 'center', fontSize: '14px', marginTop: 'auto' },

  mainContent: { flex: 1, backgroundColor: '#f5fcf9', borderTopLeftRadius: '45px', padding: '40px', overflowY: 'auto' },
  topHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' },
  breadcrumb: { color: '#999', fontSize: '13px' },
  userProfile: { display: 'flex', alignItems: 'center', backgroundColor: '#fff', padding: '10px 18px', borderRadius: '35px', boxShadow: '0 4px 12px rgba(0,0,0,0.03)' },
  userName: { marginRight: '12px', fontWeight: '600', fontSize: '14px', color: '#333' },
  avatar: { width: '32px', height: '32px', borderRadius: '50%', backgroundColor: '#f0f0f0', display: 'flex', justifyContent: 'center', alignItems: 'center' },
  contentWrapper: { padding: '0 5px' },
  welcomeText: { fontSize: '26px', fontWeight: '700', marginBottom: '35px', color: '#2c3e50' },
  statsGrid: { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '28px', marginBottom: '45px' },
  statCard: { backgroundColor: '#fff', padding: '28px', borderRadius: '22px', display: 'flex', alignItems: 'center', boxShadow: '0 8px 24px rgba(0,0,0,0.05)' },
  statIconBox: { fontSize: '30px', marginRight: '22px', width: '60px', height: '60px', backgroundColor: '#f0fbf7', borderRadius: '18px', display: 'flex', justifyContent: 'center', alignItems: 'center' },
  statValue: { fontSize: '24px', fontWeight: '700', color: '#008f68' },
  statLabel: { fontSize: '14px', color: '#999' },
  tableSection: { marginTop: '20px' },
  tableTitle: { fontSize: '18px', fontWeight: '700', marginBottom: '22px', color: '#2c3e50' },
  tableCard: { backgroundColor: '#fff', borderRadius: '25px', padding: '28px', boxShadow: '0 10px 30px rgba(0,0,0,0.02)' },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { textAlign: 'left', padding: '16px', color: '#bbb', fontSize: '12px', borderBottom: '1px solid #f8f9fa' },
  td: { padding: '20px 16px', fontSize: '14px', borderBottom: '1px solid #fcfcfc', color: '#444' },
  tr: { transition: '0.2s' },
  progressBar: { width: '130px', height: '9px', backgroundColor: '#f1f1f1', borderRadius: '12px', marginBottom: '6px' },
  progressFill: { height: '100%', borderRadius: '12px', transition: 'width 0.8s ease-in-out' },
  badgeGreen: { backgroundColor: '#d1e7dd', color: '#0f5132', padding: '7px 16px', borderRadius: '35px', fontSize: '11px', fontWeight: '700' },
  badgeRed: { backgroundColor: '#f8d7da', color: '#842029', padding: '7px 16px', borderRadius: '35px', fontSize: '11px', fontWeight: '700' },
  deleteButton: { backgroundColor: '#e74c3c', color: '#fff', border: 'none', padding: '8px 16px', borderRadius: '12px', cursor: 'pointer', fontSize: '12px', fontWeight: '600' },
};

export default Dashboard;
